    '=LET(ID;$A1000;данные;IMPORTRANGE(ID;"Список. YouTube!A:Z");заголовки;INDEX(данные;1;);метка;"3▼ Партнёр";позиция;MATCH(метка;заголовки;0);столбец;INDEX(данные;;позиция);количество;ROWS(данные);начало;MATCH(метка;столбец;0)+1;конец;MATCH("🔵";столбец;0)-1;отфильтрованные;FILTER(столбец;(SEQUENCE(количество)>=начало)*(SEQUENCE(количество)<=конец));имеетОсьминога;ARRAYFORMULA(IFERROR(FIND("🐙";отфильтрованные;1)>0;FALSE));нормализованные;ARRAYFORMULA(IF(имеетОсьминога;"🐙";""));VSTACK("Партнёр "&CHAR(10)&"SciTopus";нормализованные))',
