    '=LET(ID;$A1000;данные;IMPORTRANGE(ID;"Список. YouTube!A:Z");заголовки;INDEX(данные;1;);метка;"Посл. вид.";позиция;MATCH(метка;заголовки;0);столбец;INDEX(данные;;позиция);количество;ROWS(данные);начало;MATCH(метка;столбец;0)+1;конец;MATCH("🔵";столбец;0)-1;отфильтрованные;FILTER(столбец;(SEQUENCE(количество)>=начало)*(SEQUENCE(количество)<=конец));форматированныеГоды;ARRAYFORMULA(IF(ISNUMBER(отфильтрованные);YEAR(отфильтрованные);отфильтрованные));VSTACK("Год послед."&CHAR(10)&" видео";форматированныеГоды))',
    '=LET(ID;$A1000;данные;IMPORTRANGE(ID;"Список. YouTube!A:Z");заголовки;INDEX(данные;1;);метка;"Создан";позиция;MATCH(метка;заголовки;0);столбец;INDEX(данные;;позиция);количество;ROWS(данные);начало;MATCH(метка;столбец;0)+1;конец;MATCH("🔵";столбец;0)-1;отфильтрованные;FILTER(столбец;(SEQUENCE(количество)>=начало)*(SEQUENCE(количество)<=конец));форматированныеГоды;ARRAYFORMULA(IF(ISNUMBER(отфильтрованные);YEAR(отфильтрованные);отфильтрованные));VSTACK("Год создания"&CHAR(10)&" канала";форматированныеГоды))',
